phase1.code:
fun main() {
    // ---- Basic function ----
    println(greet("Kotlin-chan"))

    // ---- Default parameters ----
    println(greetWithDefault("Kotlin-chan"))
    println(greetWithDefault("Kotlin-chan", "Hey"))

    // ---- Named arguments ----
    println(greetWithDefault(
        name = "Kotlin-chan",
        greeting = "Hello"
    ))

    // ---- Single expression function ----
    println(add(5, 3))
    println(multiply(4, 2))

    // ---- Unit return (void) ----
    printMessage("Hello")

    // ---- Functions with no parameters ----
    println(getPi())

    // ---- Default with multiple parameters ----
    println(createUser("Alice"))
    println(createUser("Bob", 25))
    println(createUser("Charlie", 30, "charlie@example.com"))

    // ---- Named arguments with defaults ----
    // Skip age, provide email
    println(createUser(
        name = "Dave",
        email = "dave@example.com"
    ))
}

// ---- Basic function ----
fun greet(name: String): String {
    return "Hello, $name!"
}

// ---- Default parameters ----
fun greetWithDefault(name: String, greeting: String = "Hello"): String {
    return "$greeting, $name!"
}

// ---- Single expression function ----
fun add(a: Int, b: Int) = a + b
fun multiply(a: Int, b: Int) = a * b

// ---- Unit return (void) ----
fun printMessage(message: String): Unit {
    println(message)
}

// ---- No parameters ----
fun getPi(): Double = 3.14159

// ---- Multiple default parameters ----
fun createUser(
    name: String,
    age: Int = 18,
    email: String = "default@example.com"
): String {
    return "User: $name, Age: $age, Email: $email"
}

