phase3.solution:
fun greetUser(name: String, greeting: String = "Hello", excited: Boolean = false): String {
    return "$greeting, $name${if (excited) "!" else ""}!"
}

fun main() {
    println(greetUser("Alice"))
    println(greetUser("Bob", "Hey"))
    println(greetUser("Charlie", excited = true))
}
